steps.query:
query GetTransactions(
  $startDate: DateTime!
  $endDate: DateTime!
  $first: Int
) {
  campaignOrderTransactionsWithEventsesConnection(
    where: {
      transactionDate_gte: $startDate
      transactionDate_lte: $endDate
    }
    first: $first
  ) {
    edges {
      node {
        id
        orderId
        transactionDate
        revenue
        totalImpressions
        lastImpression
        attrMethod
        attrWindow
      }
    }
    aggregate {
      count
    }
    pageInfo {
      hasNextPage
      endCursor
    }
  }
}
